sql:
SELECT funds.fund_id, funds.fund_name, fund_types.type_name
FROM funds
INNER JOIN fund_types ON funds.type_id = fund_types.type_id;

SELECT
  (SELECT COUNT(*) FROM fund_managers WHERE status = 'active') AS active_managers,
  (SELECT COUNT(*) FROM funds WHERE status = 'active') AS active_funds;

SELECT fund_id, AVG(probability * impact) AS average_risk_probability
FROM fund_risks
GROUP BY fund_id;

SELECT COUNT(*) 
FROM fund_managers 
WHERE status = 'active' AND years_of_experience > 5;

SELECT fm.manager_name, fm.email, ff.fund_id
FROM fund_managers fm
JOIN fund_manager_funds ff ON fm.manager_id = ff.manager_id;

SELECT fund_name, total_assets 
FROM funds 
WHERE total_assets > (SELECT AVG(total_assets) FROM funds);
